// Smoke Signal — noise layers at different scales, heavy atmospheric feedback
speed = 0.4

AUDIO.bins = 6; AUDIO.smooth = 0.78; AUDIO.gain = 50; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

// layered noise — large + small scale blended
noise(1.5, 0.06)
  .color(
    () => 0.5 + low() * 1.0,
    () => 0.3 + mid() * 0.7,
    () => 0.6 + high() * 0.8
  )
  .blend(noise(4, 0.03).color(
    () => 0.3 + high() * 0.6,
    () => 0.5 + low() * 0.8,
    () => 0.4 + mid() * 0.6
  ), 0.4)
  .modulate(noise(0.8, 0.04), 0.1)
  .modulateRotate(noise(0.5, 0.03), 0.003)
  // very heavy feedback — this is what creates the smoke
  .blend(src(o0).hue(() => 0.004 + amp() * 0.008).colorama(() => 0.003 + low() * 0.005), 0.88)
  .saturate(() => 1.0 + low() * 0.5)
  .contrast(() => 1.02 + low() * 0.08)
  .brightness(0.03)
  .out(o0)
